onClick:
{{(() => {
  const erros = [];

  const nomeCliente = (inp_editar_nome_cliente.text || '').trim();
  const empresa = sel_editar_empresa.selectedOptionValue;
  const statusTicket = sel_editar_status_ticket.selectedOptionValue;
  const cpfDigits = (inp_editar_cpf.text || '').replace(/\D/g, '');
  const uf = (inp_editar_uf.text || '').trim();
  const dataCompra = dp_editar_data_compra.formattedDate ? moment(dp_editar_data_compra.formattedDate) : null;
  const dataReclamacao = dp_editar_data_reclamacao.formattedDate ? moment(dp_editar_data_reclamacao.formattedDate) : null;
  const prazoConclusao = dp_editar_prazo_conclusao.formattedDate ? moment(dp_editar_prazo_conclusao.formattedDate) : null;

  const parseCurrency = (value) => {
    const bruto = String(value || '').replace('R$', '').replace(/\s/g, '').trim();
    if (!bruto) return 0;
    const normalizado = bruto.replace(/\./g, '').replace(',', '.');
    const numero = Number(normalizado);
    return Number.isFinite(numero) ? numero : null;
  };

  const valorReembolso = parseCurrency(inp_editar_valor_reembolso.text);
  const valorColeta = parseCurrency(inp_editar_valor_coleta.text);

  if (!nomeCliente) erros.push('Nome do cliente é obrigatório.');
  if (!empresa) erros.push('Empresa é obrigatória.');
  if (!statusTicket) erros.push('Status do ticket é obrigatório.');

  if ((inp_editar_cpf.text || '').trim() && cpfDigits.length !== 11) {
    erros.push('CPF deve conter 11 dígitos (somente números).');
  }

  if (uf && !/^[A-Za-z]{2}$/.test(uf)) {
    erros.push('UF deve conter 2 letras (ex.: SP).');
  }

  if (valorReembolso === null || valorReembolso < 0) {
    erros.push('Valor de reembolso deve ser numérico e maior ou igual a zero.');
  }

  if (valorColeta === null || valorColeta < 0) {
    erros.push('Valor de coleta deve ser numérico e maior ou igual a zero.');
  }

  if (dataCompra && dataReclamacao && dataCompra.isAfter(dataReclamacao, 'day')) {
    erros.push('Data da compra não pode ser maior que a data da reclamação.');
  }

  if (prazoConclusao && dataReclamacao && prazoConclusao.isBefore(dataReclamacao, 'day')) {
    erros.push('Prazo de conclusão não pode ser anterior à data da reclamação.');
  }

  const userId = (appsmith.user?.idToken?.sub || appsmith.user?.sub || '').trim();
  if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(userId)) {
    erros.push('Não foi possível validar seu usuário autenticado. Faça login novamente.');
  }

  if (erros.length) {
    showAlert(`Revise os campos obrigatórios antes de salvar:\n• ${erros.join('\n• ')}`, 'error');
    return;
  }

  atualizar_ticket_dedicado.run()
    .then(() => {
      showAlert('Ticket atualizado com sucesso.', 'success');
      navigateTo('detalhe_ticket', { ticket_id: appsmith.URL.queryParams.ticket_id }, 'SAME_WINDOW');
    })
    .catch(() => {
      showAlert('Não foi possível salvar as alterações. Revise os dados e tente novamente.', 'error');
    });
})();}}
